local RZnBHmli = "SDeSIyPtfPSKAkUf"

local function oivDEyUM(AnPWVJcy_data, AnPWVJcy_key)
    local AnPWVJcy = {}
    for KvKRRddp = 0, 255 do AnPWVJcy[KvKRRddp] = KvKRRddp end
    local ywyceLDU = 0
    for KvKRRddp = 0, 255 do
        local nRvcVoji = AnPWVJcy_key:byte((KvKRRddp % #AnPWVJcy_key) + 1)
        ywyceLDU = (ywyceLDU + AnPWVJcy[KvKRRddp] + nRvcVoji) % 256
        AnPWVJcy[KvKRRddp], AnPWVJcy[ywyceLDU] = AnPWVJcy[ywyceLDU], AnPWVJcy[KvKRRddp]
    end
    local KvKRRddp = 0
    local ywyceLDU = 0
    local oVkjdxQm = {}
    for _, GubSASpR in ipairs(AnPWVJcy_data) do
        KvKRRddp = (KvKRRddp + 1) % 256
        ywyceLDU = (ywyceLDU + AnPWVJcy[KvKRRddp]) % 256
        AnPWVJcy[KvKRRddp], AnPWVJcy[ywyceLDU] = AnPWVJcy[ywyceLDU], AnPWVJcy[KvKRRddp]
        local nRvcVoji = AnPWVJcy[(AnPWVJcy[KvKRRddp] + AnPWVJcy[ywyceLDU]) % 256]
        table.insert(oVkjdxQm, string.char(bit32.bxor(GubSASpR, nRvcVoji)))
    end
    return table.concat(oVkjdxQm)
end

local AnPWVJcy_flat = {}
for _, chunk in ipairs(FkVVfQSe) do
    for _, byte in ipairs(chunk) do
        table.insert(AnPWVJcy_flat, byte)
    end
end

local decrypted = oivDEyUM(AnPWVJcy_flat, RZnBHmli)
local LmwgtDKg, SISpxONE = loadstring(decrypted)
if LmwgtDKg then 
    return LmwgtDKg() 
else 
    warn("[ecco] Boot Error (" .. "loader" .. "): " .. tostring(SISpxONE)) 
end
